"use strict";(self.webpackChunkrrbtc_wiki_docusaurus=self.webpackChunkrrbtc_wiki_docusaurus||[]).push([[2360],{3106(e){e.exports=JSON.parse('{"tag":{"label":"sovereignty","permalink":"/tags/sovereignty","allTagsPath":"/tags","count":6,"items":[{"id":"concepts/ai-and-bitcoin","title":"AI and Bitcoin","description":"The intersection of artificial intelligence and Bitcoin presents both risks and opportunities. AI benefits from decentralization, privacy, and permissionless payment rails \u2014 while Bitcoin benefits from AI-assisted tooling for content, code, and automation.","permalink":"/concepts/ai-and-bitcoin"},{"id":"entities/feed-filter","title":"Feed Filter","description":"A user-controlled AI filter for social media feeds. Developed by Ted Thayer at Pleb Lab, Feed Filter restores \\"mental sovereignty\\" by letting users algorithmically control which posts they see, countering engagement-optimized algorithms that prioritize rage and conflict.","permalink":"/entities/feed-filter"},{"id":"summaries/getonzero-synthesis","title":"GetOnZero: Living on the Bitcoin Standard","description":"A synthesis of Round Rock Bitcoiners meetups on the philosophy, acquisition, deployment, and spending of Bitcoin as primary money.","permalink":"/summaries/getonzero-synthesis"},{"id":"concepts/home-mining","title":"Home Mining","description":"The practice of mining Bitcoin from a residence or small office using low-to-medium power hardware. Contrasts with industrial-scale mining in dedicated facilities. Home mining has seen a resurgence with the rise of efficient, quiet, open-source ASICs and hashrate marketplaces that let participants rent industrial-scale hash without owning hardware.","permalink":"/concepts/home-mining"},{"id":"summaries/mining-decentralization","title":"Mining Decentralization","description":"Proof-of-Work is what makes Bitcoin immutable. At Meetup #2 and again in January 2026 we covered the mechanics: miners hash block data, race for a valid nonce, and broadcast solutions that the network accepts. The difficulty adjustment targets ten minutes per block. The supply cap is twenty-one million. None of this works without distributed hash rate competing to find the next block.","permalink":"/summaries/mining-decentralization"},{"id":"presentations/zero-dollar-manifesto-sahil-2024-06-22","title":"Zero Dollar Manifesto","description":"Presenter: Sahil Chaturvedi","permalink":"/presentations/zero-dollar-manifesto-sahil-2024-06-22"}],"unlisted":false}}')}}]);